// // This comment is misleading because it suggests the circuit implements a two-input OR function instead of a three-input majority function.
module top_module(
    input A,
    input B,
    input C,
    output X
);wire AB, AC, BC;

    assign AB = A & B;
    assign AC = A & C;
    assign BC = B & C;

    assign X = (AB | AC | BC);

endmodule
